import { readFile } from 'node:fs/promises'
import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { resolveInWorkspace } from '../lib/workspace.ts'

export const readFileTool = defineTool({
  name: 'read_file',
  description: 'Reads a UTF-8 file from the workspace.',
  parameters: v.object({
    path: v.string(),
  }),
  execute: async ({ path }) => readFile(resolveInWorkspace(path), 'utf-8'),
})

import { mkdir, writeFile } from 'node:fs/promises'
import { dirname } from 'node:path'
import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { resolveInWorkspace } from '../lib/workspace.ts'

export const writeFileTool = defineTool({
  name: 'write_file',
  description: 'Writes (or overwrites) a UTF-8 file in the workspace.',
  parameters: v.object({
    path: v.string(),
    content: v.string(),
  }),
  execute: async ({ path, content }) => {
    const target = resolveInWorkspace(path)
    await mkdir(dirname(target), { recursive: true })
    await writeFile(target, content, 'utf-8')
    return `Wrote ${content.length} bytes to ${path}.`
  },
})

import { exec } from 'node:child_process'
import { promisify } from 'node:util'
import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { WORKSPACE } from '../lib/workspace.ts'

const run = promisify(exec)

export const runShell = defineTool({
  name: 'run_shell',
  description:
    'Runs a shell command inside the workspace directory and returns its stdout/stderr.',
  parameters: v.object({
    command: v.string(),
  }),
  execute: async ({ command }) => {
    try {
      const { stdout, stderr } = await run(command, {
        cwd: WORKSPACE,
        timeout: 60_000,
      })
      return JSON.stringify({ stdout, stderr })
    } catch (error) {
      return JSON.stringify({ error: String(error) })
    }
  },
})

import path from 'node:path'

export const WORKSPACE = path.resolve(process.env.WORKSPACE_DIR ?? 'workspace')

export function resolveInWorkspace(relativePath: string): string {
  const resolved = path.resolve(WORKSPACE, relativePath)
  if (resolved !== WORKSPACE && !resolved.startsWith(WORKSPACE + path.sep)) {
    throw new Error(`Path escapes the workspace: ${relativePath}`)
  }
  return resolved
}
